.darma-loader-uiverse-heartbeat-medallion { display: inline-flex; align-items: center; justify-content: center; position: relative; }
/* heart beat */
.darma-loader-uiverse-heartbeat-medallion__heartbeatloader {
  position: relative;
  width: 72px;
  height: 72px;
  z-index: 0;
  margin: auto;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
}

.darma-loader-uiverse-heartbeat-medallion__svgdraw {
top: 30%;
left: 26%;
position: absolute;
width: 50%;
height: 50%;
color: #fff;
transform: scale(1.4);
z-index: 3;
}

.darma-loader-uiverse-heartbeat-medallion__path {
stroke: color-mix(in srgb, var(--loader-secondary-color, #ffffff) 95%, transparent);
stroke-width: 4;
stroke-dasharray: 1000px;
stroke-dashoffset: 1000px;
animation: darma-loader-uiverse-heartbeat-medallion-draw 1.5s infinite forwards normal linear;
animation-delay: 0.1s;
position: relative;
}

@keyframes darma-loader-uiverse-heartbeat-medallion-draw {
to {
stroke-dashoffset: 0;
}
}

.darma-loader-uiverse-heartbeat-medallion__innercircle {
position: absolute;
top: 17%;
left: 100.5%;
transform: translate(-50%, -50%) scale(1.2);
width: 160%;
height: auto;
z-index: 1;
opacity: 0.97;
animation: darma-loader-uiverse-heartbeat-medallion-innerbeat 1.5s infinite linear forwards;
}

.darma-loader-uiverse-heartbeat-medallion__innercircle:before,
.darma-loader-uiverse-heartbeat-medallion__innercircle:after {
position: absolute;
content: "";
left: 25%;
top: 0;
width: 25%;
height: auto;
padding-bottom: 40%;
background: var(--loader-color, #e15f5f);
border-radius: 50px 50px 0 0;
transform: rotate(-45deg);
transform-origin: 0 100%;
}

.darma-loader-uiverse-heartbeat-medallion__innercircle:after {
left: 0;
transform: rotate(45deg);
transform-origin: 100% 100%;
}

@keyframes darma-loader-uiverse-heartbeat-medallion-innerbeat {
0% {
transform: translate(-50%, -50%) scale(1.2);
}

10% {
transform: translate(-50%, -50%) scale(1.2);
}

50% {
transform: translate(-50%, -50%) scale(1.3);
}

60% {
transform: translate(-50%, -50%) scale(1.25);
}

75% {
transform: translate(-50%, -50%) scale(1.3);
}
}

.darma-loader-uiverse-heartbeat-medallion__outercircle {
width: 100%;
height: 100%;
border-radius: 50%;
background-color: rgba(238, 92, 92, 0.9);
box-shadow: 0 0 30px 0px #fff;
position: absolute;
z-index: -1;
opacity: 0.7;
top: 0;
left: 0;
transform: scale(1.2);
animation: darma-loader-uiverse-heartbeat-medallion-outerbeat 1.5s infinite linear forwards;
}

@keyframes darma-loader-uiverse-heartbeat-medallion-outerbeat {
0% {
transform: scale(1.2);
}

10% {
transform: scale(1.2);
}

50% {
transform: scale(1.3);
}

60% {
transform: scale(1.25);
}

75% {
transform: scale(1.3);
}
}

